insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'beginner', 'Lernst du jeden Tag?', 'Do you study every day?', 'هل تتعلم كل يوم؟', 'Apprends-tu tous les jours ?');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'beginner', 'Wir lernen zusammen.', 'We study together.', 'نتعلم معًا.', 'Nous apprenons ensemble.');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'beginner', 'Er lernt für die Prüfung.', 'He is studying for the exam.', 'يدرس من أجل الامتحان.', 'Il étudie pour l''examen.');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'beginner', 'Die Kinder lernen schnell.', 'The children learn quickly.', 'الأطفال يتعلمون بسرعة.', 'Les enfants apprennent vite.');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'intermediate', 'Sie hat gestern drei Stunden gelernt.', 'She studied for three hours yesterday.', 'درست لمدة ثلاث ساعات أمس.', 'Elle a étudié trois heures hier.');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'intermediate', 'Man lernt nie aus.', 'You learn something new every day.', 'لا يتوقف المرء عن التعلم أبدًا.', 'On n''arrête jamais d''apprendre.');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'intermediate', 'Ich lerne Deutsch, seit ich in Berlin wohne.', 'I''ve been learning German since I moved to Berlin.', 'أتعلم الألمانية منذ أن انتقلت إلى برلين.', 'J''apprends l''allemand depuis que j''habite à Berlin.');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'intermediate', 'Für diesen Beruf muss man viel lernen.', 'You have to study a lot for this profession.', 'لهذه المهنة يجب أن تدرس كثيرًا.', 'Pour ce métier, il faut beaucoup étudier.');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'intermediate', 'Ohne Fleiß kein Preis - man muss hart lernen.', 'No pain no gain - you have to work hard.', 'بدون اجتهاد لا نجاح - يجب أن تدرس بجد.', 'Sans effort, pas de récompense - il faut étudier dur.');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'advanced', 'Die Studierenden lernen die komplexen Zusammenhänge der Quantenphysik.', 'The students are learning the complex relationships of quantum physics.', 'يدرس الطلاب العلاقات المعقدة لفيزياء الكم.', 'Les étudiants apprennent les relations complexes de la physique quantique.');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'advanced', 'Aus Fehlern lernt man, sagt man - aber nur, wenn man reflektiert.', 'You learn from mistakes, they say - but only if you reflect.', 'من الأخطاء يتعلم المرء، كما يقال - ولكن فقط إذا تأمل.', 'On apprend de ses erreurs, dit-on - mais seulement si on réfléchit.');
insert into public.verb_examples (verb_id, difficulty, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'advanced', 'Zeitlebens zu lernen ist in unserer sich schnell wandelnden Gesellschaft unerlässlich.', 'Lifelong learning is essential in our rapidly changing society.', 'التعلم مدى الحياة أمر أساسي في مجتمعنا سريع التغير.', 'Apprendre tout au long de la vie est essentiel dans notre société en évolution rapide.');
