insert into public.verb_typical_questions (verb_id, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'Was lernst du gerade?', 'What are you learning right now?', 'ماذا تتعلم الآن؟', 'Qu''apprends-tu en ce moment ?');
insert into public.verb_typical_questions (verb_id, german, english, arabic, french) values ((select id from public.german_verbs where slug = 'lernen'), 'Wie lange lernst du schon Deutsch?', 'How long have you been learning German?', 'منذ متى وأنت تتعلم الألمانية؟', 'Depuis combien de temps apprends-tu l''allemand ?');
insert into public.verb_common_mistakes (verb_id, incorrect, correct, explanation, arabic_explanation, french_explanation) values ((select id from public.german_verbs where slug = 'lernen'), 'Ich lerne für Deutsch.', 'Ich lerne Deutsch.', 'lernen takes accusative directly. You don''t need für before the subject.', 'الفعل lernen يأخذ المفعول به مباشرة بدون حرف جر.', 'Le verbe lernen prend l''accusatif directement, sans préposition.');
insert into public.verb_prefix_explanations (verb_id, prefix, explanation, example, english_explanation) values ((select id from public.german_verbs where slug = 'lernen'), 'er-', 'Erlernen implies mastering, achieving complete knowledge through learning.', 'erlernen - to master (a skill)', 'The prefix er- often indicates achieving or reaching a goal through the action.');
insert into public.verb_learning_tips (verb_id, tip_type, content) values ((select id from public.german_verbs where slug = 'lernen'), 'memory_trick', 'Think learnin'' - like English learning but with the German -en ending.');
insert into public.verb_learning_tips (verb_id, tip_type, content) values ((select id from public.german_verbs where slug = 'lernen'), 'usage_notes', 'Lernen is used for acquiring knowledge or skills. For to teach, use lehren (jemanden etwas lehren).');
insert into public.verb_learning_tips (verb_id, tip_type, content) values ((select id from public.german_verbs where slug = 'lernen'), 'common_contexts', 'Used in school contexts (für die Schule lernen), language learning (Deutsch lernen), and professional development (einen Beruf lernen).');
insert into public.verb_learning_tips (verb_id, tip_type, content) values ((select id from public.german_verbs where slug = 'lernen'), 'formal_vs_informal', 'Lernen is neutral. In formal contexts, prefer sich bilden or sich weiterbilden');
